      --border:       #E5E5E1;
      --border-2:     #CECEC8;
      --primary:      #1C3DB8;
      --primary-bg:   #EDF0FB;
      --bull:         #B93027;
      --bull-bg:      #FAF0EF;
      --bull-border:  #EEC4C1;
      --bear:         #0B7A52;
      --bear-bg:      #EAF5EF;
      --bear-border:  #AEDAC7;
      --watch:        #A85C08;
      --watch-bg:     #FDF5E8;
      --watch-border: #EACF9E;
      --text-1:       #0C0C0C;
      --text-2:       #555555;
      --text-3:       #999999;
      --nav-h:        56px;
      --max-w:        1280px;
      --r:            12px;
      --font-serif:   'Songti SC', STSong, SimSun, serif;
