# 直接调 API 看数据结构
echo "=== 事件列表 ==="
curl -s "https://stocks.matraceai.com/api/events/" 2>/dev/null | python3 -m json.tool 2>/dev/null | head -120

echo ""
echo "=== 统计信息 ==="
curl -s "https://stocks.matraceai.com/api/events/" 2>/dev/null | python3 -c "
import json, sys
data = json.load(sys.stdin)
if isinstance(data, dict):
    print('Keys:', list(data.keys()))
    if 'results' in data:
        print('Total:', data.get('count', 'N/A'))
        print('Results count:', len(data['results']))
        if data['results']:
            ev = data['results'][0]
            print('First event keys:', list(ev.keys()))
            for k,v in ev.items():
                if not isinstance(v, (list, dict)):
                    print(f'  {k}: {v}')
                elif isinstance(v, list) and v and isinstance(v[0], dict):
                    print(f'  {k}: [{len(v)} items] first keys: {list(v[0].keys())}')
            # show stocks detail
            if ev.get('stocks'):
                print()
                print('=== First event stocks ===')
                for s in ev['stocks']:
                    print(f'  {s}')
elif isinstance(data, list):
    print('Type: list, count:', len(data))
    if data:
        print('First item keys:', list(data[0].keys()))
"
